import { LifecycleOption, LifecycleState } from '../types';

// @ts-ignore
const IS_SAFARI = typeof safari === 'object' && safari.pushNotification;

const SUPPORTS_PAGE_TRANSITION_EVENTS = 'onpageshow' in self;


const EVENTS = [
  'focus',
  'blur',
  'visibilitychange',
  'freeze',
  'resume',
  'pageshow',
  SUPPORTS_PAGE_TRANSITION_EVENTS ? 'pagehide' : 'unload',
];

const toIndexedObject = (arr) => arr.reduce((acc, val, idx) => {
  acc[val] = idx;
  return acc;
}, {});

const LEGAL_STATE_TRANSITIONS = [
  [LifecycleState.ACTIVE, LifecycleState.PASSIVE, LifecycleState.HIDDEN, LifecycleState.TERMINATED],
  [LifecycleState.ACTIVE, LifecycleState.PASSIVE, LifecycleState.HIDDEN, LifecycleState.FROZEN],
  [LifecycleState.HIDDEN, LifecycleState.PASSIVE, LifecycleState.ACTIVE],
  [LifecycleState.FROZEN, LifecycleState.HIDDEN],
  [LifecycleState.FROZEN, LifecycleState.ACTIVE],
  [LifecycleState.FROZEN, LifecycleState.PASSIVE],
].map(toIndexedObject);

export default class Lifecycle {
	private _state: LifecycleState;
	private _safariBeforeUnloadTimeout: any;
	private lifycycleHandle: (event: Event, state: LifecycleState) => void;

	constructor(options: LifecycleOption) {
		try {
      this.lifycycleHandle = options.lifecycleHandle;
      this._state = this.getPageCurrentState();
      this._handleEvents = this._handleEvents.bind(this);

      EVENTS.forEach((event) => addEventListener(event, this._handleEvents, true));
      if (IS_SAFARI) {
        addEventListener('beforeunload', (evt) => {
          this._safariBeforeUnloadTimeout = setTimeout(() => {
          if (!(evt.defaultPrevented || evt.returnValue.length > 0)) {
            this._dispatchChangesIfNeeded(evt, LifecycleState.HIDDEN);
          }
          }, 0);
        });
      }
    } catch (error) {
      console.error(error);
    }
	}

	getPageCurrentState() {
		if (document.visibilityState === LifecycleState.HIDDEN) {
				return LifecycleState.HIDDEN;
		}
		if (document.hasFocus()) {
				return LifecycleState.ACTIVE;
		}
		return LifecycleState.PASSIVE;
	};

  getLegalStateTransitionPath(oldState: LifecycleState, newState: LifecycleState) {
    try {
      for (let order, i = 0; order = LEGAL_STATE_TRANSITIONS[i]; ++i) {
        const oldIndex = order[oldState];
        const newIndex = order[newState];
    
        if (oldIndex >= 0 && newIndex >= 0 && newIndex > oldIndex) {
          return Object.keys(order).slice(oldIndex, newIndex + 1) as LifecycleState[];
        }
      }
      return [];
    } catch (error) {
      console.error(error);
      return [];
    }
  };

	_dispatchChangesIfNeeded(originalEvent: Event, newState: LifecycleState) {
    try {
      if (newState !== this._state) {
        const oldState = this._state;
        const path = this.getLegalStateTransitionPath(oldState, newState);
  
        for (let i = 0; i < path.length - 1; ++i) {
          const oldState = path[i];
          const newState = path[i + 1];
  
          this._state = newState;
          this.lifycycleHandle(originalEvent, newState);
        }
      }
    } catch (error) {
      console.error(error);
    }
  }

	_handleEvents(evt) {
		try {
      if (IS_SAFARI) {
        clearTimeout(this._safariBeforeUnloadTimeout);
      }
  
      switch (evt.type) {
        case 'pageshow':
        case 'resume':
          this._dispatchChangesIfNeeded(evt, this.getPageCurrentState());
          break;
        case 'focus':
          this._dispatchChangesIfNeeded(evt, LifecycleState.ACTIVE);
          break;
        case 'blur':
          if (this._state === LifecycleState.ACTIVE) {
            this._dispatchChangesIfNeeded(evt, this.getPageCurrentState());
          }
          break;
        case 'pagehide':
        case 'unload':
          this._dispatchChangesIfNeeded(evt, evt.persisted ? LifecycleState.FROZEN : LifecycleState.TERMINATED);
          break;
        case 'visibilitychange':
          if (this._state !== LifecycleState.FROZEN && this._state !== LifecycleState.TERMINATED) {
            this._dispatchChangesIfNeeded(evt, this.getPageCurrentState());
          }
          break;
        case 'freeze':
          this._dispatchChangesIfNeeded(evt, LifecycleState.FROZEN);
          break;
      }
    } catch (error) {
      console.error(error);
    }
  }

  /**
   * 用于Tea实例销毁时移除相应页面监听器
   */
  removePageEventListener() {
    EVENTS.forEach((event) => removeEventListener(event, this._handleEvents, true));
  }
};